from typing import Optional, Tuple


def get_authorization_scheme_param(
    authorization_header_value: Optional[str],
) -> Tuple[str, str]:
    """Extract the authorization scheme and parameter from an Authorization header value.

    Args:
        authorization_header_value: The raw Authorization header value, for example
            "Bearer <token>" or "Basic <credentials>".

    Returns:
        A tuple of two strings: (scheme, param). 'scheme' is the authorization scheme
        (e.g., "Bearer"), and 'param' is the credential or token that follows. If the
        header value is missing or empty, returns two empty strings.
    """
    if not authorization_header_value:
        return "", ""
    scheme, _, param = authorization_header_value.partition(" ")
    return scheme, param